#include<iostream>
using namespace std;
bool a[1005][1005];
int qzh[1005][1005];
int main(void){
	ios::sync_with_stdio(false);cin.tie(0);
	int n,m,k;cin>>n>>m>>k;
	for(int i=1;i<=n;i++){
		for(int j=1;j<=m;j++){
			char c;cin>>c;
			a[i][j]=c-'0';
			qzh[i][j]=qzh[i-1][j]+qzh[i][j-1]-qzh[i-1][j-1]+a[i][j];
		}
	}
	int ans=0x3f3f3f3f;
	for(int x1=0;x1<n;x1++){
		for(int y1=0;y1<m;y1++){
			for(int x2=x1;x2<=n;x2++){
				for(int y2=y1;y2<=m;y2++){
					int x=qzh[x2][y2]-qzh[x2][y1]-qzh[x1][y2]+qzh[x1][y1];
					if(x>=k)ans=min(ans,(x2-x1)*(y2-y1));
				}
			}
		}
	}
	cout<<((ans==0x3f3f3f3f)?0:ans);
	return false;
}
